import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { name, email, subject, message } = req.body;

  if (!name || !email || !message) {
    return res.status(400).json({ error: 'Missing required fields' });
  }

  try {
    const data = await resend.emails.send({
      from: 'DriveDE Feedback <system@drivede.app>',
      to: ['your-personal-email@example.com'], // The user should replace this or we can use an env var
      replyTo: email,
      subject: `New Feedback: ${subject || 'General Inquiry'}`,
      html: `
        <div style="font-family: sans-serif; color: #1e293b; max-width: 600px;">
          <h2 style="color: #3b82f6;">New Feedback from ${name}</h2>
          <p><strong>Email:</strong> ${email}</p>
          <p><strong>Subject:</strong> ${subject || 'N/A'}</p>
          <div style="background: #f1f5f9; padding: 20px; border-radius: 12px; margin-top: 20px;">
            ${message.replace(/\n/g, '<br />')}
          </div>
        </div>
      `
    });

    return res.status(200).json({ success: true, data });
  } catch (error) {
    return res.status(500).json({ error: 'Failed to send email' });
  }
}

/**
 * DriveDE Overpass API Proxy
 * 
 * Bypasses CORS and Origin blocking by forwarding requests from the server.
 * Includes a custom User-Agent to comply with Overpass usage policies.
 */

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { data: query } = req.body;

  if (!query) {
    return res.status(400).json({ error: 'Missing Overpass query' });
  }

  const endpoints = [
    'https://overpass-api.de/api/interpreter',
    'https://lz4.overpass-api.de/api/interpreter',
    'https://z.overpass-api.de/api/interpreter',
    'https://overpass.osm.ch/api/interpreter',
    'https://overpass.kumi.systems/api/interpreter'
  ];

  // Randomize start endpoint to balance load
  const shuffledEndpoints = [...endpoints].sort(() => Math.random() - 0.5);

  for (const endpoint of shuffledEndpoints) {
    try {
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'User-Agent': 'DriveDE/1.0 (https://drive-de.vercel.app)'
        },
        body: `data=${encodeURIComponent(query)}`,
      });

      if (response.ok) {
        const data = await response.json();
        return res.status(200).json(data);
      }

      console.warn(`[OverpassProxy] Endpoint ${endpoint} returned status: ${response.status}`);
    } catch (error) {
      console.error(`[OverpassProxy] Error fetching from ${endpoint}:`, error);
    }
  }

  return res.status(502).json({ error: 'All Overpass endpoints failed' });
}

import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  // Verification token from Supabase (optional security)
  const webhookSecret = req.headers['x-supabase-webhook-secret'];
  if (webhookSecret !== process.env.SUPABASE_WEBHOOK_SECRET) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  const { record } = req.body;
  const email = record.email;
  const fullName = record.raw_user_meta_data?.full_name || 'Future Driver';

  try {
    const data = await resend.emails.send({
      from: 'DriveDE <welcome@drivede.app>',
      to: [email],
      subject: 'Welcome to DriveDE! 🚗',
      html: `
        <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; color: #1e293b;">
          <h1 style="color: #3b82f6; font-size: 32px; font-weight: 900; margin-bottom: 24px;">Welcome aboard, ${fullName}!</h1>
          <p style="font-size: 16px; line-height: 1.6; margin-bottom: 20px;">
            We're thrilled to have you join the DriveDE family. Your account is now confirmed, and you're ready to start your journey towards getting your German driving license.
