function addPdfWrappedText(
  pdf: jsPDF,
  text: string,
  x: number,
  y: number,
  maxWidth: number,
  lineHeight: number,
  pageHeight: number,
  bottomMargin: number
) {
  const lines = pdf.splitTextToSize(text, maxWidth) as string[];
  let cursorY = y;

  lines.forEach((line) => {
    if (cursorY > pageHeight - bottomMargin) {
      pdf.addPage();
      cursorY = 20;
    }
    pdf.text(line, x, cursorY);
    cursorY += lineHeight;
  });

  return cursorY;
}

function addPdfSectionTitle(pdf: jsPDF, title: string, y: number, pageHeight: number, bottomMargin: number) {
  let cursorY = y;
  if (cursorY > pageHeight - bottomMargin - 12) {
    pdf.addPage();
    cursorY = 20;
  }

  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(15);
  pdf.text(title, 14, cursorY);
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(11);
  return cursorY + 8;
}

